local OIIllIlIOII=111
local OIOlOl0lOIl=117
local OllOI00OO0l="ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
local function Oll0lOO0Oll(d)
    d=(d or ""):gsub("%s+","")
    d=d:gsub("[^"..OllOI00OO0l.."=]","")
    return (d:gsub(".",function(x)
        if x=="=" then return "" end
        local r,f="",(OllOI00OO0l:find(x,1,true)-1)
        for i=6,1,-1 do
            r=r..(f%2^i-f%2^(i-1)>0 and "1" or "0")
        end
        return r
    end):gsub("%d%d%d?%d?%d?%d?%d?%d?",function(x)
        if #x~=8 then return "" end
        local c=0
        for i=1,8 do
            if x:sub(i,i)=="1" then c=c+2^(8-i) end
        end
        return string.char(c)
    end))
end
local function OOI0l00lOll(a,b)
    local r,m=0,1
    while a>0 or b>0 do
        local aa=a%2
        local bb=b%2
        if aa~=bb then r=r+m end
        a=(a-aa)/2
        b=(b-bb)/2
        m=m*2
    end
    return r
end
local O0lIOOIlOOl=OO0OIIIO0lI:gsub("[^A-Za-z0-9+/=]","")
O0lIOOIlOOl=string.reverse(O0lIOOIlOOl)
local O00IOllOIlO=Oll0lOO0Oll(O0lIOOIlOOl)
local OlOOO0lOOIl={}
for OOIIOII0l00=1,#O00IOllOIlO do
    local O00OlIOllll=O00IOllOIlO:byte(OOIIOII0l00)
    local OO0l0OI00l0=(O00OlIOllll-((OIOlOl0lOIl+OOIIOII0l00)%256))%256
    OlOOO0lOOIl[OOIIOII0l00]=string.char(OOI0l00lOll(OO0l0OI00l0,OIIllIlIOII))
end
local Ol0l0OOIOl0=table.concat(OlOOO0lOOIl)
local Ol0IllIlO00=loadstring or load
local OII0lO0llI0,O0IOlOIl0OI=Ol0IllIlO00(Ol0l0OOIOl0)
if not OII0lO0llI0 then error(O0IOlOIl0OI) end
return OII0lO0llI0()
